// SPDX-License-Identifier: GPL-3.0

pragma solidity >=0.7.0 <0.9.0;

/** 
 * @title Ballot
 * @dev Implements voting process along with vote delegation
 */
contract Ballot {
    // This declares a new complex type which will
    // be used for variables later.
    // It will represent a single voter.
    struct Voter {
        uint weight; // weight is accumulated by delegation
        bool voted;  // if true, that person already voted
        address delegate; // person delegated to
        uint vote;   // index of the voted proposal
    }

    // This is a type for a single proposal.
    struct Proposal {
        // If you can limit the length to a certain number of bytes, 
        // always use one of bytes1 to bytes32 because they are much cheaper
        bytes32 name;   // short name (up to 32 bytes)
        uint voteCount; // number of accumulated votes
    }

    address public chairperson;

    // This declares a state variable that
    // stores a 'Voter' struct for each possible address.
    mapping(address => Voter) public voters;

    // A dynamically-sized array of 'Proposal' structs.
    Proposal[] public proposals;

    /** 
     * @dev Create a new ballot to choose one of 'proposalNames'.
     * @param proposalNames names of proposals
     */
    constructor(bytes32[] memory proposalNames) {
        chairperson = msg.sender;
        voters[chairperson].weight = 1;

        // For each of the provided proposal names,
        // create a new proposal object and add it
        // to the end of the array.
        for (uint i = 0; i < proposalNames.length; i++) {
            // 'Proposal({...})' creates a temporary
            // Proposal object and 'proposals.push(...)'
            // appends it to the end of 'proposals'.
            proposals.push(Proposal({
                name: proposalNames[i],
                voteCount: 0
            }));
        }
    }

     /** 
     * @dev Give 'voter' the right to vote on this ballot. May only be called by 'chairperson'.
     * @param voter address of voter
     */
    function giveRightToVote(address voter) external {
        // If the first argument of `require` evaluates
        // to 'false', execution terminates and all
        // changes to the state and to Ether balances
        // are reverted.
        // This used to consume all gas in old EVM versions, but
        // not anymore.
        // It is often a good idea to use 'require' to check if
        // functions are called correctly.
        // As a second argument, you can also provide an
        // explanation about what went wrong.
        require(
            msg.sender == chairperson,
            "Only chairperson can give right to vote."
        );
        require(
            !voters[voter].voted,
            "The voter already voted."
        );
        require(voters[voter].weight == 0, "Voter already has the right to vote.");
        voters[voter].weight = 1;
    }

    /**
     * @dev Delegate your vote to the voter 'to'.
     * @param to address to which vote is delegated
     */
    function delegate(address to) external {
        // assigns reference
        Voter storage sender = voters[msg.sender];
        require(sender.weight != 0, "You have no right to vote");
        require(!sender.voted, "You already voted.");

        require(to != msg.sender, "Self-delegation is disallowed.");

        // Forward the delegation as long as
        // 'to' also delegated.
        // In general, such loops are very dangerous,
        // because if they run too long, they might
        // need more gas than is available in a block.
        // In this case, the delegation will not be executed,
        // but in other situations, such loops might
        // cause a contract to get "stuck" completely.
        while (voters[to].delegate != address(0)) {
            to = voters[to].delegate;

            // We found a loop in the delegation, not allowed.
            require(to != msg.sender, "Found loop in delegation.");
        }

        Voter storage delegate_ = voters[to];

        // Voters cannot delegate to accounts that cannot vote.
        require(delegate_.weight >= 1);

        // Since 'sender' is a reference, this
        // modifies 'voters[msg.sender]'.
        sender.voted = true;
        sender.delegate = to;

        if (delegate_.voted) {
            // If the delegate already voted,
            // directly add to the number of votes
            proposals[delegate_.vote].voteCount += sender.weight;
        } else {
            // If the delegate did not vote yet,
            // add to her weight.
            delegate_.weight += sender.weight;
        }
    }

    /**
     * @dev Give your vote (including votes delegated to you) to proposal 'proposals[proposal].name'.
     * @param proposal index of proposal in the proposals array
     */
    function vote(uint proposal) external {
        Voter storage sender = voters[msg.sender];
        require(sender.weight != 0, "Has no right to vote");
        require(!sender.voted, "Already voted.");
        sender.voted = true;
        sender.vote = proposal;

        // If 'proposal' is out of the range of the array,
        // this will throw automatically and revert all
        // changes.
        proposals[proposal].voteCount += sender.weight;
    }

    /** 
     * @dev Computes the winning proposal taking all previous votes into account.
     * @return winningProposal_ index of winning proposal in the proposals array
     */
    function winningProposal() public view
            returns (uint winningProposal_)
    {
        uint winningVoteCount = 0;
        for (uint p = 0; p < proposals.length; p++) {
            if (proposals[p].voteCount > winningVoteCount) {
                winningVoteCount = proposals[p].voteCount;
                winningProposal_ = p;
            }
        }
    }

    /** 
     * @dev Calls winningProposal() function to get the index of the winner contained in the proposals array and then
     * @return winnerName_ the name of the winner
     */
    function winnerName() external view
            returns (bytes32 winnerName_)
    {
        winnerName_ = proposals[winningProposal()].name;
    }
}

contracts/Callee.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity >=0.8.18 <0.9.0;

contract Callee {
    uint256 public data;


    event DataStored(address indexed sender, uint256 data);

    function storeData(uint256 _data) public {
        data = _data;

        emit DataStored(msg.sender, _data);
    }
}

contracts/ProfileStatus.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.18;

contract ProfileStatus{
    // 在favoriteNumber中，mapping是将名字作为一个查询的key
    // 如果名字重名了，那么mapping就造成冲突了
    // 这里解决这个问题就是使用地址来解决
    // 定义一个结构体
    struct Status{
        string name; // 
        string message;
    }
    // 创建一个mapping将地址和结构体关联起来
    mapping(address => Status) private userStatus;

    function createOrUpdate(string memory _name, string memory _message) public {
        // 这里调用的时候不知道地址是什么？
        // 这里通过内置方法获取
        // 在合约调用这个方法的时候，会传入地址from、to等
        userStatus[msg.sender].name = _name;
        userStatus[msg.sender].message = _message;
    }
    function getStatus() public view returns (string memory, string memory) {
        return (userStatus[msg.sender].name, userStatus[msg.sender].message);
    }
}

contracts/TipJar.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.18;

// 创建一个合约部署到虚拟环境以太坊上
// 
contract TipJar {
    address public owner;

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner{
        require(msg.sender == owner, "you are not owner");
        _; // 下划线代表是别的方法的逻辑
    }

    function tip() public payable {
        // 转账金额必须大于0
        require(msg.value > 0, "Tip amount must be greater than 0");
    }
    // 提现
    function withDraw() public onlyOwner {
        // 这里的withDraw是一个public方法，意味着任何人都可以调用这个方法
        // 所以这里加一个限制条件
        // 这里也可以使用装饰器来完成这个操作, 定义一个装饰器onlyOwner，再将onlyOwner装饰器
        // 放在定义的方法后面，就可以执行拦截操作
        // require(msg.sender == owner, "you are not owner");
        // 1、查询余额（solidity中有内置方法）
        // 2、将余额提现到owner中
       uint256 contractBalance = address(this).balance;
       // 这里可以加入一些限制,只有余额大于0才可以执行转账
       // solidity从0.7.0开始支持unicode，第二个参数就可以传任意类型的utf-8字符
       require(contractBalance > 0, unicode"这里没有可提现的余额");
       payable(owner).transfer(contractBalance);
    }
    // 获取余额
    function getBalance() public view returns (uint256) {
        return address(this).balance;
    }
}

contracts/FavoriteNumber.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.18;

contract FavoriteNumber{
    /**
        实现的功能：
        将名字和他喜欢的数字一一对应起来
    */
    mapping (string => uint256) private nameToFavoriteNumber;

    // 定义public，让这个方法可以在外部调用
    // 这里定义memory是因为string是一个动态大小的类型，所以使用memory指定这个参数在函数执行过程中放在内存里面
    // uint256是一个简单的值类型，大小是固定的
    function createOrUpdateNumber(string memory name, uint256 number) public {
        nameToFavoriteNumber[name] = number;
    }
    // 加上view这个关键字，表示这个函数只是读取数据，不会做任何修改
    // 如果是pure，那么这个函数既不能修改也不能读取，但是这个函数读取了mapping的数据结构
    function getNumber(string memory name) public view returns (uint256) {
        return nameToFavoriteNumber[name];
    }
}
